mapper.select:
select a.resource_id, a.system_code, a.resource_source_pk_id, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_desc, a.owner_type, a.catalog_id, a.man_org_id, a.man_user_id, a.create_by, a.create_time, a.update_time, a.com_acct_id, a.resource_status, a.resource_code, a.publish_time, a.resource_d_verid, a.resource_r_verid, a.shelf_time, a.unshelf_time, a.auth_status, a.publish_portal, e.tag_name, e.skills, c.user_name as createUserName, d.org_name as manOrgName, e.create_type from ss_resource a left join ss_res_ext_dig_employee e on a.resource_id = e.resource_id left join ss_resource_catalog b on a.catalog_id = b.catalog_id left join po_users c on a.create_by = c.user_id left join po_organization d on a.man_org_id = d.org_id left join ( select grant_obj_id, sum(case when grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as red_count, sum(case when grant_to_type = 'BLACK' and status_cd = 'A' then 1 else 0 end) as black_count, sum(case when grant_type = 'FORCE_USE' and status_cd = 'A' then 1 else 0 end) as force_use_count, sum(case when grant_type = 'AVAILABLE_USE' and status_cd = 'A' then 1 else 0 end) as available_use_count, sum(case when grant_type = 'ALLOW_MANAGE' and status_cd = 'A' then 1 else 0 end) as allow_manage_count from au_privilege_grant where grant_type in ('AVAILABLE_USE', 'FORCE_USE', 'ALLOW_MANAGE') and grant_obj_type = 'DIG_EMPLOYEE' and status_cd in ('A')
or ( grant_to_obj_type = 'ORG' and grant_to_obj_id in
#{orgId}
)
or (grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId})
or ( grant_to_obj_type = 'POST' and grant_to_obj_id in
#{positionId}
)
or (grant_to_obj_type = 'STATION' and grant_to_obj_id = #{userStationId})
group by grant_obj_id ) k on a.resource_id = k.grant_obj_id left join ( select grant_obj_id, count(1) as pending_apply_count, sum(case when grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId} then 1 else 0 end) as my_pending_apply_count from au_privilege_grant where grant_type = 'AVAILABLE_USE' and grant_to_type = 'RED' and status_cd = 'P' group by grant_obj_id ) p on a.resource_id = p.grant_obj_id
and a.resource_biz_type = 'DIG_EMPLOYEE' and a.owner_type = 'enterprise' and (k.black_count = 0 or k.black_count is null)
and a.create_by = #{userId}
and (k.force_use_count > 0 or k.available_use_count > 0)
and k.allow_manage_count > 0
and a.system_code in
#{item}
and a.catalog_id in
#{catalogIdItem}
and a.catalog_id = #{catalogId}
and a.man_org_id in
#{orgId}
and a.publish_type = #{publishType}
and a.resource_status = #{resourceStatus}
and a.create_by = #{userId}
and (a.create_by is null or a.create_by != #{userId}) and (k.force_use_count > 0 or k.available_use_count > 0 or k.allow_manage_count > 0)
and coalesce(p.pending_apply_count, 0) > 0 and ( a.create_by = #{userId} or k.allow_manage_count > 0
or 1 = 1
or exists ( select 1 from po_organization org where org.org_id = a.man_org_id and (
org.path_code = #{pathCode} or org.path_code like concat(#{pathCode}, '.%')
) )
)
and coalesce(p.my_pending_apply_count, 0) > 0
and ( a.resource_name like concat('%', #{keyword}, '%') or a.resource_desc like concat('%', #{keyword}, '%'))

select a.resource_id, a.system_code, a.resource_source_pk_id, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_desc, a.avatar, a.catalog_id, a.man_org_id, a.man_user_id, a.create_by, a.create_time, a.com_acct_id, a.resource_status, a.owner_type, a.resource_code, a.publish_time, a.shelf_time, a.unshelf_time, a.auth_status, a.publish_portal, b.agent_type, b.agent_home_url, b.prologue, b.integration_type, b.agent_dev_type, b.create_type, b.terminal, b.tag_name, b.skills, b.open_super_helper, c.user_name as createUserName, d.org_name as manOrgName from ss_resource a left join ss_res_ext_dig_employee b on a.resource_id = b.resource_id left join ss_resource_catalog cat on a.catalog_id = cat.catalog_id left join po_users c on a.create_by = c.user_id left join po_organization d on a.man_org_id = d.org_id left join ( select grant_obj_id, sum(case when grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as red_count, sum(case when grant_to_type = 'BLACK' and status_cd = 'A' then 1 else 0 end) as black_count, sum(case when grant_type = 'FORCE_USE' and status_cd = 'A' then 1 else 0 end) as force_use_count, sum(case when grant_type = 'AVAILABLE_USE' and status_cd = 'A' then 1 else 0 end) as available_use_count, sum(case when grant_type = 'ALLOW_MANAGE' and status_cd = 'A' then 1 else 0 end) as allow_manage_count from au_privilege_grant where grant_type in ('AVAILABLE_USE', 'FORCE_USE', 'ALLOW_MANAGE') and grant_obj_type = 'DIG_EMPLOYEE' and status_cd in ('A')
or ( grant_to_obj_type = 'ORG' and grant_to_obj_id in
#{orgId}
)
or (grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId})
or ( grant_to_obj_type = 'POST' and grant_to_obj_id in
#{positionId}
)
or (grant_to_obj_type = 'STATION' and grant_to_obj_id = #{userStationId})
group by grant_obj_id ) k on a.resource_id = k.grant_obj_id left join ( select grant_obj_id, count(1) as pending_apply_count, sum(case when grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId} then 1 else 0 end) as my_pending_apply_count from au_privilege_grant where grant_type = 'AVAILABLE_USE' and grant_to_type = 'RED' and status_cd = 'P' group by grant_obj_id ) p on a.resource_id = p.grant_obj_id
and a.resource_biz_type = 'DIG_EMPLOYEE' and (
(a.owner_type = 'personal_default' and a.resource_id = #{defaultDigEmployeeId}) or
(a.owner_type = 'personal_default' and a.resource_code = #{defaultSuperAssistantResourceCode}) or
a.resource_status = #{resourceStatus}
1 = 1
a.resource_status = 2
)
and (k.black_count = 0 or k.black_count is null) and ( ( a.owner_type = 'personal' and ( a.create_by = #{userId} or k.allow_manage_count > 0 or k.red_count > 0 or k.force_use_count > 0 or k.available_use_count > 0 ) )
or ( a.owner_type = 'personal_default'
or a.resource_id = #{defaultDigEmployeeId}
or a.resource_code = #{defaultSuperAssistantResourceCode}
)
)
and a.system_code in
#{item}
and a.catalog_id in
#{catalogIdItem}
and a.catalog_id = #{catalogId}
and a.create_by = #{userId}
and a.owner_type = 'personal' and (a.create_by is null or a.create_by != #{userId}) and (k.red_count > 0 or k.allow_manage_count > 0)
and coalesce(p.pending_apply_count, 0) > 0 and ( a.create_by = #{userId} or k.allow_manage_count > 0
or 1 = 1
or exists ( select 1 from po_organization org where org.org_id = a.man_org_id and (
org.path_code = #{pathCode} or org.path_code like concat(#{pathCode}, '.%')
) )
or ( a.owner_type = 'personal_default'
or a.resource_id = #{defaultDigEmployeeId}
or a.resource_code = #{defaultSuperAssistantResourceCode}
)
)
and coalesce(p.my_pending_apply_count, 0) > 0
and ( a.resource_name like concat('%', #{keyword}, '%') or a.resource_desc like concat('%', #{keyword}, '%') )
order by COALESCE(a.update_time, '1970-01-01 00:00:00') desc, a.create_time desc

SELECT a.resource_id, a.resource_code, a.system_code, a.resource_source_pk_id, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_desc, a.avatar, a.sample, a.tags, a.resource_version_id, a.host_type, a.catalog_id, a.man_org_id, a.man_user_id, a.index_list, a.create_by, a.create_time, a.update_by, a.update_time, a.com_acct_id, a.resource_status, a.resource_d_verid, a.resource_r_verid, b.resource_id, b.agent_type, b.agent_dev_type, b.agent_sse_head, b.agent_sse_url, b.agent_web_url, b.agent_admin_url_list, b.prologue, b.agent_home_url, b.home_type, b.agent_sse_url_ori, b.agent_web_url_ori, b.agent_admin_url_ori_list, b.create_type, b.auth_type, b.integration_type, b.ability, b.constraints, b.faqs, b.role_attributes, b.processing_flow, b.personality_dimensions, b.word_preferences, b.sentence_and_tone, b.terminal FROM ss_resource a LEFT JOIN ss_res_ext_dig_employee b ON a.resource_id = b.resource_id
AND a.resource_biz_type = 'DIG_EMPLOYEE'
AND a.resource_id =#{resourceId}
AND a.resource_code =#{resourceCode}
